mapper.insert:
INSERT INTO WORKSPACE ( ID
                      , WS_NM
                      , WS_DESC
                      , WS_OWNER_ID
                      , REGIST_DT)
VALUES ( #{id,        jdbcType=VARCHAR}
       , #{wsNm,      jdbcType=VARCHAR}
       , #{wsDesc,    jdbcType=VARCHAR}
       , #{wsOwnerId, jdbcType=VARCHAR}
       , NOW())

INSERT INTO WORKSPACE_USER ( ID
                           , WS_ID
                           , USER_ID
                           , AUTHORITY
                           , REGIST_DT)
VALUES ( #{id,        jdbcType=VARCHAR}
       , #{wsId,      jdbcType=VARCHAR}
       , #{userId,    jdbcType=VARCHAR}
       , #{authority,  jdbcType=VARCHAR}
       , NOW())
